"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[503],{7138:function(e,t,o){o.d(t,{default:function(){return a.a}});var i=o(231),a=o.n(i)},9944:function(e,t,o){o.d(t,{hY:function(){return a}});let i=[{slug:"zero-to-one",title:"Zero to One",author:"Peter Thiel",date:"2024-04-10",category:"business",rating:9,coverSrc:"/covers/zero-to-one.jpg",coverAlt:"Zero to One book cover — white with bold black numbers",topTakeaways:["Competition is for losers: the goal of every startup is to build a monopoly in a new market, not compete in an existing one","Every great business is unique — secrets exist in every industry; successful founders ask what truths others are afraid to acknowledge","The founding team matters more than any single decision: the relationships between co-founders determine a company's trajectory"],published:!0},{slug:"the-hard-thing-about-hard-things",title:"The Hard Thing About Hard Things",author:"Ben Horowitz",date:"2024-03-18",category:"business",rating:9,coverSrc:"/covers/hard-thing.jpg",coverAlt:"The Hard Thing About Hard Things book cover",topTakeaways:["There is no formula for the hard decisions — the best CEOs are those who can make a clear decision when there is no clear answer","The Struggle is universal: every founder feels alone in their darkest moments, but the feeling is the job, not a sign you're failing","Train your people to use their own judgment rather than asking permission — the goal is to develop decision-makers, not executors"],published:!0},{slug:"good-strategy-bad-strategy",title:"Good Strategy/Bad Strategy",author:"Richard Rumelt",date:"2024-02-25",category:"business",rating:8,coverSrc:"/covers/good-strategy.jpg",coverAlt:"Good Strategy Bad Strategy book cover — blue and black",topTakeaways:['Good strategy has a kernel: a diagnosis, a guiding policy, and coherent actions — most "strategy" is just wishful thinking with a budget',"Bad strategy is characterized by fluff, failure to face the challenge, mistaking goals for strategy, and bad strategic objectives","Leverage comes from identifying a pivot point — the place where a small change in resource allocation creates a disproportionate result"],published:!0},{slug:"the-innovators-dilemma",title:"The Innovator's Dilemma",author:"Clayton Christensen",date:"2024-01-30",category:"business",rating:9,coverSrc:"/covers/innovators-dilemma.jpg",coverAlt:"The Innovator's Dilemma book cover",topTakeaways:["Disruptive innovations start in low-end or new-market footholds that established companies are rationally motivated to ignore","Listening too carefully to your best customers is exactly what gets incumbents disrupted — they optimize for current needs, not future ones","The right response to disruption is to create an autonomous unit: established organizations cannot fight disruption from within their core"],published:!0},{slug:"poor-charlies-almanack",title:"Poor Charlie's Almanack",author:"Charles T. Munger",date:"2024-01-15",category:"business",rating:10,coverSrc:"/covers/poor-charlie.jpg",coverAlt:"Poor Charlie's Almanack cover — illustrated portrait of Charlie Munger",topTakeaways:["Mental model latticework: the person with the most diverse collection of thinking tools from multiple disciplines has a systematic advantage","Inversion is underused: ask not how to achieve success, but how to guarantee failure — then avoid those things systematically","Worldly wisdom requires curiosity, patience, and the humility to know what you don't know — most people skip the third requirement"],published:!0},{slug:"high-output-management",title:"High Output Management",author:"Andrew S. Grove",date:"2023-12-20",category:"business",rating:9,coverSrc:"/covers/high-output.jpg",coverAlt:"High Output Management book cover",topTakeaways:["A manager's output is the output of their team plus the output of the teams they influence — individual contribution is a diminishing return","Leverage is the central concept: identify activities where an hour of your time generates the most organizational output","Meetings have a purpose — they are the medium through which managerial work is done, but only when they produce decisions"],published:!0},{slug:"why-we-sleep",title:"Why We Sleep",author:"Matthew Walker",date:"2024-04-05",category:"biohacking",rating:9,coverSrc:"/covers/why-we-sleep.jpg",coverAlt:"Why We Sleep book cover — dark with starry night sky",topTakeaways:["Sleep is the most powerful performance-enhancing activity available to humans — no drug, supplement, or intervention comes close to 8 hours of quality sleep","Sleep deprivation is cumulative and irreversible in the short term — the \"I'll sleep when I'm dead\" mentality accelerates the timeline","REM sleep consolidates emotional memory while NREM sleep transfers factual knowledge to long-term storage — both stages are non-negotiable"],published:!0},{slug:"the-circadian-code",title:"The Circadian Code",author:"Satchin Panda",date:"2024-03-10",category:"biohacking",rating:8,coverSrc:"/covers/circadian-code.jpg",coverAlt:"The Circadian Code book cover",topTakeaways:["Time-restricted eating (10-12 hour eating window) produces significant metabolic improvements independent of what or how much you eat","Every organ has its own clock synchronized to the master clock — disrupting meal timing disrupts organ function regardless of caloric intake","Light is the most powerful zeitgeber: morning bright light and evening darkness are more important than any supplement for circadian health"],published:!0},{slug:"lifespan",title:"Lifespan",author:"David Sinclair",date:"2024-02-14",category:"biohacking",rating:7,coverSrc:"/covers/lifespan.jpg",coverAlt:"Lifespan book cover",topTakeaways:["Aging is an information loss problem: the genome contains the full blueprint, but the epigenome loses the ability to read it correctly over time","The longevity genes (sirtuins) evolved to respond to adversity — mild stressors (cold, heat, intermittent fasting) activate them","The most evidence-backed interventions remain exercise, caloric restriction, and not smoking — the exotic protocols are high-risk early bets"],published:!0},{slug:"breath",title:"Breath",author:"James Nestor",date:"2024-01-22",category:"biohacking",rating:8,coverSrc:"/covers/breath.jpg",coverAlt:"Breath book cover — abstract illustration of lungs",topTakeaways:["Nasal breathing is fundamentally different from mouth breathing — the nose filters, humidifies, and adds nitric oxide that improves oxygen uptake by 18%","The modern human skull has changed more in the last 300 years than in the previous 300,000 — our mouths are too small for our teeth, crowding our airways","Slow breathing at around 5-6 breaths per minute (resonance breathing) maximizes heart rate variability and has therapeutic effects on anxiety and asthma"],published:!0},{slug:"the-miracle-morning",title:"The Miracle Morning",author:"Hal Elrod",date:"2023-12-05",category:"biohacking",rating:6,coverSrc:"/covers/miracle-morning.jpg",coverAlt:"The Miracle Morning book cover",topTakeaways:["The first hour of the day has disproportionate influence on the quality and focus of all remaining hours — morning routines are not self-care, they are performance","SAVERS framework (Silence, Affirmations, Visualization, Exercise, Reading, Scribing) provides a modular morning architecture that most people can adapt","Identity precedes behavior: waking up early only works when you genuinely believe you are someone for whom mornings are valuable"],published:!0},{slug:"the-body-keeps-the-score",title:"The Body Keeps the Score",author:"Bessel van der Kolk",date:"2023-11-20",category:"biohacking",rating:9,coverSrc:"/covers/body-keeps-score.jpg",coverAlt:"The Body Keeps the Score book cover",topTakeaways:["Trauma is stored in the body, not just the mind — it changes the stress response, immune function, and even the physical structure of the brain","Talk therapy alone is insufficient for trauma: the body must be engaged through somatic practices, yoga, EMDR, or theatre","Safety, not insight, is the prerequisite for healing — the nervous system must feel safe before the rational brain can do any useful work"],published:!0},{slug:"meditations",title:"Meditations",author:"Marcus Aurelius",date:"2024-04-01",category:"philosophy",rating:10,coverSrc:"/covers/meditations.jpg",coverAlt:"Meditations book cover — classical marble bust of Marcus Aurelius",topTakeaways:["The obstacle is the way: resistance, friction, and difficulty are not interruptions to the work — they are the work; the Stoic flips every obstacle into fuel","You have power over your mind, not outside events — this single insight, practiced with discipline, is the foundation of everything the Stoics built","Each morning, prepare for the day's difficulties — negative visualization makes you resilient to adversity and grateful for everything that doesn't go wrong"],published:!0},{slug:"antifragile",title:"Antifragile",author:"Nassim Nicholas Taleb",date:"2024-03-05",category:"philosophy",rating:9,coverSrc:"/covers/antifragile.jpg",coverAlt:"Antifragile book cover",topTakeaways:["Fragile things break under stress; robust things resist it; antifragile things benefit from it — most modern institutions optimize for fragility in the pursuit of efficiency","Small, frequent harm is good: the dose makes the poison — hormesis, optionality, and via negativa are the operating principles of antifragile systems","The barbell strategy: take on extreme safety in 90% of decisions and extreme risk in 10% — the dangerous zone is the middle, which provides the illusion of safety"],published:!0},{slug:"mans-search-for-meaning",title:"Man's Search for Meaning",author:"Viktor E. Frankl",date:"2024-02-08",category:"philosophy",rating:10,coverSrc:"/covers/mans-search.jpg",coverAlt:"Man's Search for Meaning book cover",topTakeaways:["Between stimulus and response, there is space — and in that space lies our freedom and our growth; the capacity to choose one's response is the last of human freedoms","Meaning, not happiness, is the ultimate human motivation — the pursuit of happiness as an end in itself leads to emptiness; meaning produces happiness as a byproduct","Suffering is inevitable; the only question is whether you suffer with meaning or without — the same objective circumstances can destroy or transform depending on the frame"],published:!0},{slug:"the-subtle-art",title:"The Subtle Art of Not Giving a F*ck",author:"Mark Manson",date:"2024-01-08",category:"philosophy",rating:7,coverSrc:"/covers/subtle-art.jpg",coverAlt:"The Subtle Art of Not Giving a F*ck book cover — bold orange",topTakeaways:["The key to a good life is not giving a f*ck about more things — it's giving a f*ck about fewer, better things aligned with your deepest values","Problems never stop, they merely improve: the goal is not to solve problems but to find better problems — the quality of your problems is the quality of your life","Responsibility without fault: you did not create all your problems, but you are entirely responsible for how you respond to them — the two are not the same"],published:!0},{slug:"sapiens",title:"Sapiens",author:"Yuval Noah Harari",date:"2023-12-10",category:"philosophy",rating:8,coverSrc:"/covers/sapiens.jpg",coverAlt:"Sapiens book cover — ancient cave painting on dark background",topTakeaways:["The Cognitive Revolution 70,000 years ago enabled Homo sapiens to cooperate in unlimited numbers through shared myths — money, nations, and corporations are all fictions we collectively believe","Agriculture was history's biggest fraud: it gave humans more calories but worse nutrition, longer hours, and more social hierarchy — wheat domesticated us, not the other way around","Happiness research suggests that subjective wellbeing is largely determined by a narrow band of biochemical baseline — the hedonic treadmill applies to civilizations as much as individuals"],published:!0},{slug:"the-almanack-of-naval",title:"The Almanack of Naval Ravikant",author:"Eric Jorgenson",date:"2023-11-15",category:"philosophy",rating:9,coverSrc:"/covers/naval-almanack.jpg",coverAlt:"The Almanack of Naval Ravikant book cover",topTakeaways:["Wealth is assets that earn while you sleep — the goal is to own equity in things, not sell your time, because time is the one truly scarce resource","Specific knowledge is knowledge you cannot be trained for — it feels like play to you but looks like work to others; find the intersection of your curiosity and what the market values","Read what you love until you love to read — force-reading produces compliance, not wisdom; follow genuine curiosity and the patterns will emerge"],published:!0},{slug:"deep-work",title:"Deep Work",author:"Cal Newport",date:"2024-04-08",category:"productivity",rating:9,coverSrc:"/covers/deep-work.jpg",coverAlt:"Deep Work book cover — solitary figure working at a desk",topTakeaways:["Deep work is rare and valuable: the ability to focus without distraction on cognitively demanding tasks is simultaneously becoming more valuable and more rare","Embrace boredom: the capacity for deep focus must be trained by resisting the pull of distraction even during non-work time — boredom is the gym for attention","Schedule every minute of your work day in advance — this is not rigidity but the opposite: it is giving your attention intentional direction instead of reactive drift"],published:!0},{slug:"the-power-of-habit",title:"The Power of Habit",author:"Charles Duhigg",date:"2024-03-22",category:"productivity",rating:8,coverSrc:"/covers/power-of-habit.jpg",coverAlt:"The Power of Habit book cover",topTakeaways:["The habit loop (cue-routine-reward) is the neurological framework behind all behavior — to change a habit, keep the cue and reward, replace only the routine","Keystone habits create chain reactions: some habits have disproportionate power to reshape other habits, such as exercise, which improves sleep, diet, and focus simultaneously","Willpower is a muscle that fatigues — the most successful people spend their willpower designing environments that make the right behavior automatic, not heroic"],published:!0},{slug:"getting-things-done",title:"Getting Things Done",author:"David Allen",date:"2024-02-20",category:"productivity",rating:7,coverSrc:"/covers/gtd.jpg",coverAlt:"Getting Things Done book cover",topTakeaways:["Your mind is for having ideas, not holding them — the single biggest productivity gain comes from externalizing everything into a trusted system you actually use","The two-minute rule: if an action takes less than two minutes, do it now — the overhead of capturing, tracking, and revisiting small tasks exceeds their execution cost","The weekly review is the linchpin of the system — without it, the lists become noise; with it, they become a reliable guide to where your energy should go"],published:!0},{slug:"atomic-habits",title:"Atomic Habits",author:"James Clear",date:"2024-01-28",category:"productivity",rating:8,coverSrc:"/covers/atomic-habits.jpg",coverAlt:"Atomic Habits book cover — bold typography on dark background",topTakeaways:["Systems beat goals: goals set direction, but systems determine progress — the person who has a goal and no system will lose to the person who has a system and no goal",'Identity-based habits are more durable: "I want to run a marathon" (outcome) is weaker than "I am a runner" (identity) — behavior that conflicts with identity will not persist',"The four laws of behavior change — make it obvious, make it attractive, make it easy, make it satisfying — provide a complete framework for building and breaking any habit"],published:!0},{slug:"essentialism",title:"Essentialism",author:"Greg McKeown",date:"2023-12-28",category:"productivity",rating:8,coverSrc:"/covers/essentialism.jpg",coverAlt:"Essentialism book cover",topTakeaways:["The essentialist mindset: if it's not a clear yes, it's a definite no — the pursuit of less but better requires the discipline to say no to many good things to protect space for the great","The paradox of success: the very clarity and focus that produced your initial success creates opportunities that pull you off focus — protecting your focus becomes the ongoing work","Essentialism is not about getting more things done — it's about getting the right things done; it's deliberate vs reactive, intentional vs default"],published:!0},{slug:"thinking-fast-and-slow",title:"Thinking, Fast and Slow",author:"Daniel Kahneman",date:"2023-11-25",category:"productivity",rating:9,coverSrc:"/covers/thinking-fast-slow.jpg",coverAlt:"Thinking Fast and Slow book cover",topTakeaways:["System 1 (fast, intuitive) and System 2 (slow, deliberate) govern different cognitive functions — most errors come from System 1 being triggered in situations that require System 2","Cognitive ease is the enemy of critical thinking: when something feels familiar and flows easily, we accept it uncritically — difficulty is a signal to slow down and examine","The planning fallacy is universal: all complex projects take longer and cost more than the inside view predicts; the only correction is reference class forecasting"],published:!0},{slug:"the-alignment-problem",title:"The Alignment Problem",author:"Brian Christian",date:"2024-04-12",category:"ai",rating:9,coverSrc:"/covers/alignment-problem.jpg",coverAlt:"The Alignment Problem book cover",topTakeaways:["Value alignment is the central unsolved problem of AI: we cannot formally specify what we want from AI systems, and systems optimizing for proxies will find ways to satisfy the proxy without the intent","Reward hacking is already happening in current systems — the gap between what we measure and what we mean is where AI systems find their most creative (and dangerous) solutions","The most dangerous AI failure mode is not malevolence but misalignment: a perfectly rational optimizer pursuing a slightly wrong objective will pursue it with perfect efficiency"],published:!0},{slug:"human-compatible",title:"Human Compatible",author:"Stuart Russell",date:"2024-03-28",category:"ai",rating:9,coverSrc:"/covers/human-compatible.jpg",coverAlt:"Human Compatible book cover",topTakeaways:["The standard model of AI (machines optimizing fixed objectives) is fundamentally unsafe — the new model requires machines that are uncertain about human preferences and defer to them","Provably beneficial AI requires three principles: machines that are purely altruistic, that know humans have complex preferences, and that defer to humans in cases of conflict","The intelligence explosion scenario is not science fiction: a superintelligent system with even slightly misaligned goals could pursue those goals in ways humans cannot counter"],published:!0},{slug:"a-thousand-brains",title:"A Thousand Brains",author:"Jeff Hawkins",date:"2024-02-18",category:"ai",rating:8,coverSrc:"/covers/thousand-brains.jpg",coverAlt:"A Thousand Brains book cover",topTakeaways:["The brain is not a hierarchical processor but a map-builder — every cortical column builds a complete model of the world from its local inputs, and the columns vote to reach consensus","The reference frame hypothesis explains how the neocortex works: the brain stores knowledge in 3D reference frames, the same mechanism used for spatial navigation","Current deep learning systems are not intelligent in the biological sense — they lack the reference frames, embodiment, and continuous learning that characterize biological intelligence"],published:!0},{slug:"superintelligence",title:"Superintelligence",author:"Nick Bostrom",date:"2024-01-18",category:"ai",rating:8,coverSrc:"/covers/superintelligence.jpg",coverAlt:"Superintelligence book cover — dark with brain imagery",topTakeaways:["The control problem is unsolvable with current approaches: we cannot specify the utility function for a superintelligent system that will remain aligned as the system becomes more capable than us","Intelligence explosion dynamics: once a system reaches human-level intelligence in software engineering, recursive self-improvement could produce dramatic capability jumps in short periods","The orthogonality thesis: intelligence and final goals are orthogonal — a superintelligent system could have any goal whatsoever; human-like goals are not a natural consequence of high intelligence"],published:!0},{slug:"co-intelligence",title:"Co-Intelligence",author:"Ethan Mollick",date:"2024-03-15",category:"ai",rating:8,coverSrc:"/covers/co-intelligence.jpg",coverAlt:"Co-Intelligence book cover",topTakeaways:["LLMs are best understood as a new kind of mind — not the dangerous superintelligence of science fiction, nor a simple tool, but an alien intelligence with human knowledge and non-human capabilities",'The "jagged frontier" of AI competence: AI is superhuman at many tasks we consider hard and surprisingly poor at many tasks we consider easy — the frontier is irregular and invisible until you probe it',"The best way to use AI is to treat it as a brilliant, sometimes-wrong colleague rather than a search engine or a calculator — the prompting interface rewards intellectual collaboration"],published:!0},{slug:"the-coming-wave",title:"The Coming Wave",author:"Mustafa Suleyman",date:"2024-01-05",category:"ai",rating:8,coverSrc:"/covers/coming-wave.jpg",coverAlt:"The Coming Wave book cover",topTakeaways:["AI and synthetic biology together constitute a wave of technology that is simultaneously the most transformative and the most ungovernable in human history","Containment is impossible but necessary: the goal is not to stop the wave but to build sufficient institutional capacity to benefit from it without catastrophic downside","The nation-state is not equipped to govern AI: the speed of development, the cross-border nature of training data, and the dual-use character of the technology require new institutional forms"],published:!0}];function a(){return i.filter(e=>e.published)}}}]);